mapper.update:
update model_call_ledger set logical_status='CANCEL_REQUESTED', transport_status='DETACHED',
duration_ms=#{durationMs}, updated_at=#{updatedAt}
where invocation_id=#{invocationId} and logical_status='RUNNING' and transport_status='ACTIVE'

update model_call_ledger set logical_status='TIMEOUT', transport_status='DETACHED',
duration_ms=#{durationMs}, error_category=#{errorCategory}, updated_at=#{updatedAt}
where invocation_id=#{invocationId} and logical_status='RUNNING' and transport_status='ACTIVE'

update model_call_ledger set logical_status='TIMEOUT', transport_status='TERMINATED',
duration_ms=#{durationMs}, finished_at=#{finishedAt}, updated_at=#{finishedAt}
where invocation_id=#{invocationId} and logical_status='TIMEOUT' and transport_status='DETACHED'

update model_call_ledger set logical_status='CANCELLED', transport_status='TERMINATED',
duration_ms=#{durationMs}, finished_at=#{finishedAt}, updated_at=#{finishedAt}
where invocation_id=#{invocationId}
  and logical_status in ('RUNNING','CANCEL_REQUESTED')
  and transport_status in ('ACTIVE','DETACHED')

update model_call_ledger set logical_status='TIMEOUT', transport_status='HARD_TIMEOUT',
duration_ms=#{durationMs}, error_category=#{errorCategory},
error_summary='Invocation exceeded transport hard timeout', finished_at=#{finishedAt}, updated_at=#{finishedAt}
where invocation_id=#{invocationId}
  and ((logical_status='RUNNING' and transport_status='ACTIVE')
    or (logical_status in ('CANCEL_REQUESTED','TIMEOUT') and transport_status='DETACHED'))

mapper.select:
select  from model_call_ledger
where started_at>=#{startedAt} and started_at<#{endedAt}
and user_id=#{userId}
and provider_type_snapshot=#{providerType}
and model_name_snapshot=#{modelName}
and scenario=#{scenario}
and logical_status=#{logicalStatus}
order by started_at desc, id desc

select provider_type_snapshot as provider_type, model_name_snapshot as model_name, scenario,
       logical_status, transport_status, count(*) as invocation_count,
       coalesce(sum(input_tokens),0) as input_tokens,
       coalesce(sum(output_tokens),0) as output_tokens,
       coalesce(sum(total_tokens),0) as total_tokens,
       coalesce(sum(duration_ms),0) as duration_ms
from model_call_ledger
where started_at>=#{startedAt} and started_at<#{endedAt}
and user_id=#{userId}
and provider_type_snapshot=#{providerType}
and model_name_snapshot=#{modelName}
and scenario=#{scenario}
and logical_status=#{logicalStatus}
and transport_status=#{transportStatus}
group by provider_type_snapshot, model_name_snapshot, scenario, logical_status, transport_status
order by provider_type_snapshot, model_name_snapshot, scenario, logical_status, transport_status
